  "name": "@psyforge/headless",
  "version": "1.0.0",
  "description": "WebAssembly-compiled ForgeScript runtime for high-performance simulation and testing",
  "main": "./dist/src/index.js",
  "module": "./dist/src/index.js",
  "types": "./dist/src/index.d.ts",
