    "@psyforge/forgescript": "^1.0.0"
  },
  "devDependencies": {
    "@types/node": "^20.0.0",
    "@vitest/coverage-v8": "^1.0.0",
    "assemblyscript": "^0.27.0",
    "vitest": "^1.0.0"
  },
  "keywords": [
    "psychology",
    "experiment",
    "simulation",
    "wasm",
