    "type": "git",
    "url": "https://github.com/psycho-forge/psyforge.git",
    "directory": "packages/headless"
  }
}

/**
 * @psyforge/headless - WebAssembly-based experiment simulation
 * 
 * This package provides high-performance, deterministic simulation
 * of psychology experiments with configurable cognitive models
 * and virtual devices.
 */

// Core runner
export { HeadlessRunner } from './HeadlessRunner';

// Cognitive models
export {
  SimpleRTCognitiveModel,
  StroopCognitiveModel,
  NBackCognitiveModel,
  VisualSearchCognitiveModel,
  CognitiveModelFactory,
  CognitiveModels
} from './CognitiveModels';

// Virtual devices
export {
  VirtualKeyboardDevice,
  VirtualMouseDevice,
  VirtualEyeTrackerDevice,
  VirtualEEGDevice,
  VirtualDeviceFactory
} from './VirtualDevices';

// Types
export type {
  // Core types
  HeadlessConfig,
  SimulationState,
  SimulationResults,
  MemoryMetrics,

  // Cognitive model types
  CognitiveModel,
  CognitiveModelPresets,
  SimpleRTModel,
  StroopModel,
  NBackModel,
  VisualSearchModel,

  // Participant types
  ParticipantState,
  ParticipantResults,
  ParticipantSummary,

  // Trial and metrics types
  TrialResult,
  PerformanceMetrics,
  AggregateMetrics,
  ConditionMetrics,
  PerformanceReport,

  // Virtual device types
  VirtualDevice,
  VirtualKeyboard,
  VirtualMouse,
  VirtualEyeTracker,
  VirtualEEG,

  // Export types
  ExportConfig
} from './types';

