/**
 * @psyforge/ai-assistant
 * AI-powered experiment design assistance types
 */

import { z } from 'zod';
import type { CompiledExperiment } from '@psyforge/forgescript';

/**
 * Supported AI models for experiment design assistance
 */
export type AIModel = 'gpt-4' | 'gpt-4-turbo' | 'gpt-3.5-turbo' | 'claude-3-opus' | 'claude-3-sonnet' | 'claude-3-haiku';

/**
 * Design command intents that can be parsed from natural language
 */
export type DesignIntent = 
  | 'add_stimulus'
  | 'add_trial'
  | 'add_block'
  | 'modify_timing'
  | 'add_condition'
  | 'add_response'
  | 'configure_experiment'
  | 'add_instruction'
  | 'set_parameter'
  | 'generate_factorial'
  | 'add_randomization'
  | 'add_break'
  | 'validate_design'
  | 'explain_concept'
  | 'suggest_improvement';

/**
 * Context about the current experiment state
 */
export interface ExperimentContext {
  /** The current experiment being edited */
