  /**
   * Generate response collection code
   */
  private generateResponse(params: Record<string, any>): string {
    const { type = 'keyboard', keys = ['space'], timeout = 3000, correct } = params;

    let code = `.response('${type}')\n`;

    if (type === 'keyboard') {
      code += `  .keys(${JSON.stringify(keys)})\n`;
      if (correct) code += `  .correctKey('${correct}')\n`;
    }

    code += `  .timeout(${timeout})`;

    return code;
  }

  /**
   * Generate instruction screen code
   */
  private generateInstruction(params: Record<string, any>): string {
    const { text, fontSize = 20, continueKey = 'space' } = params;

    return `experiment()
  .instruction(\`${text}\`)
    .fontSize(${fontSize})
    .continueKey('${continueKey}');`;
  }

  /**
   * Generate factorial design code
   */
  private generateFactorial(params: Record<string, any>): string {
    const { factors = {} } = params;
    const factorEntries = Object.entries(factors);

    if (factorEntries.length === 0) {
      return '// No factors specified for factorial design';
    }

    let code = `// Factorial design: ${factorEntries.map(([k, v]) => `${k}(${Array.isArray(v) ? v.length : 0})`).join(' x ')}\n`;
    code += `experiment()\n`;
    code += `  .conditions({\n`;

    factorEntries.forEach(([factor, levels], idx) => {
      code += `    ${factor}: ${JSON.stringify(levels)}`;
      if (idx < factorEntries.length - 1) code += ',';
      code += '\n';
    });

    code += `  })\n`;
    code += `  .factorial()\n`;
    code += `  .trial('factorial_trial', (condition) => {\n`;
    code += `    // Configure trial based on condition\n`;
    code += `    console.log('Condition:', condition);\n`;
    code += `  });`;

    return code;
  }

  /**
   * Generate randomization code
   */
  private generateRandomization(params: Record<string, any>): string {
    const { type = 'shuffle', seed } = params;

    let code = '';

    if (type === 'shuffle') {
      code += `// Shuffle trials\n`;
      code += `.shuffle()`;
      if (seed) code += `\n  .seed(${seed})`;
    } else if (type === 'latin_square') {
      code += `// Latin square counterbalancing\n`;
      code += `.latinSquare()`;
    }

    return code;
  }

  /**
   * Generate break screen code
   */
  private generateBreak(params: Record<string, any>): string {
    const { message = 'Take a break. Press SPACE to continue.', duration } = params;

    let code = `experiment()\n`;
    code += `  .break('${message}')`;

    if (duration) {
      code += `\n    .minimumDuration(${duration})`;
    }

    code += `;`;

    return code;
  }
}

