/**
 * Code validator for AI-generated ForgeScript
 */

import type { ValidationResult, ValidationError, ValidationWarning } from './types.js';

/**
 * Validates ForgeScript code for correctness and best practices
 */
export class CodeValidator {
  /**
   * Validate ForgeScript code
   */
  async validate(code: string): Promise<ValidationResult> {
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    // Syntax validation
    this.validateSyntax(code, errors);

    // Semantic validation
    this.validateSemantics(code, errors, warnings);

    // Timing validation
    this.validateTiming(code, errors, warnings);

    // Best practices
    this.validateBestPractices(code, warnings);

    // Performance assessment
    const performanceImpact = this.assessPerformance(code);

    return {
      valid: errors.length === 0,
      errors,
      warnings,
      performanceImpact
    };
  }

  /**
   * Validate syntax
   */
  private validateSyntax(code: string, errors: ValidationError[]): void {
    // Check for basic syntax issues
    const lines = code.split('\n');
    let openParens = 0;
    let openBraces = 0;
    let openBrackets = 0;

    lines.forEach((line, lineNum) => {
      // Count parentheses
      for (const char of line) {
        if (char === '(') openParens++;
        if (char === ')') openParens--;
        if (char === '{') openBraces++;
        if (char === '}') openBraces--;
        if (char === '[') openBrackets++;
        if (char === ']') openBrackets--;
      }

      // Check for common syntax errors
      if (line.includes('experiment()') && !line.trim().startsWith('//')) {
        // Ensure experiment() is at start of chain
        if (!line.trim().startsWith('experiment()') && 
            !line.trim().startsWith('for') && 
            !line.includes('=')) {
          errors.push({
            type: 'syntax',
            message: 'experiment() should start a new chain',
            line: lineNum + 1
          });
        }
      }

      // Check for missing semicolons (heuristic)
      if (line.trim() && 
          !line.trim().endsWith(';') && 
          !line.trim().endsWith('{') && 
          !line.trim().endsWith(',') &&
          !line.includes('//') &&
          lineNum < lines.length - 1) {
        const nextLine = lines[lineNum + 1].trim();
        if (nextLine && !nextLine.startsWith('.')) {
          errors.push({
            type: 'syntax',
            message: 'Missing semicolon',
            line: lineNum + 1,
            column: line.length
          });
        }
      }
    });

    // Check for unmatched delimiters
    if (openParens !== 0) {
      errors.push({
        type: 'syntax',
        message: `Unmatched parentheses (${openParens > 0 ? 'missing )' : 'extra )'})`
      });
    }
    if (openBraces !== 0) {
      errors.push({
        type: 'syntax',
        message: `Unmatched braces (${openBraces > 0 ? 'missing }' : 'extra }'})`
      });
    }
    if (openBrackets !== 0) {
      errors.push({
        type: 'syntax',
        message: `Unmatched brackets (${openBrackets > 0 ? 'missing ]' : 'extra ]'})`
      });
    }
  }

  /**
   * Validate semantics
   */
  private validateSemantics(
    code: string, 
    errors: ValidationError[], 
    warnings: ValidationWarning[]
  ): void {
    // Check for stimulus without duration
    const stimulusRegex = /\.stimulus\([^)]+\)(?![\s\S]*?\.duration\(\d+\))/g;
    const stimulusMatches = code.match(stimulusRegex);
    if (stimulusMatches) {
      warnings.push({
        type: 'bestpractice',
        message: 'Stimulus without explicit duration will use default',
        suggestion: 'Add .duration() to specify display time'
      });
    }

    // Check for response without timeout
    const responseRegex = /\.response\([^)]+\)(?![\s\S]*?\.timeout\(\d+\))/g;
    const responseMatches = code.match(responseRegex);
    if (responseMatches) {
      warnings.push({
        type: 'bestpractice',
        message: 'Response collection without timeout may wait indefinitely',
        suggestion: 'Add .timeout() to prevent hanging'
      });
    }

    // Check for trial without response
    const trialRegex = /\.trial\([^)]+\)[\s\S]*?(?=\.trial|experiment\(\)|$)/g;
    const trials = code.match(trialRegex) || [];
    trials.forEach(trial => {
      if (!trial.includes('.response(')) {
        warnings.push({
          type: 'bestpractice',
          message: 'Trial without response collection',
          suggestion: 'Add .response() to collect participant data'
        });
      }
    });
  }

  /**
   * Validate timing constraints
   */
  private validateTiming(
    code: string, 
    errors: ValidationError[], 
    warnings: ValidationWarning[]
  ): void {
    // Extract all duration values
    const durationRegex = /\.duration\((\d+)\)/g;
    let match;
    const durations: number[] = [];

    while ((match = durationRegex.exec(code)) !== null) {
      durations.push(parseInt(match[1]));
    }

    // Check for very short durations
    durations.forEach(duration => {
      if (duration < 16) {
        errors.push({
          type: 'timing',
          message: `Duration ${duration}ms is shorter than one frame (16.67ms)`,
        });
      } else if (duration < 50) {
        warnings.push({
          type: 'performance',
          message: `Very short duration (${duration}ms) may not display reliably`,
          suggestion: 'Consider using at least 50ms for reliable display'
        });
      }
    });

    // Check for timing precision claims
    if (durations.some(d => d % 16.67 > 0 && d % 16.67 < 1)) {
      warnings.push({
        type: 'performance',
        message: 'Durations not aligned to frame boundaries may show variance',
        suggestion: 'Use multiples of 16.67ms for frame-aligned timing'
      });
    }
  }

  /**
   * Validate best practices
   */
  private validateBestPractices(code: string, warnings: ValidationWarning[]): void {
    // Check for missing practice trials
    if (!code.includes('practice') && code.includes('trial')) {
      warnings.push({
        type: 'bestpractice',
        message: 'Consider adding practice trials before main experiment',
        suggestion: 'Add a practice block with example trials'
      });
    }

    // Check for missing instructions
    if (!code.includes('instruction')) {
      warnings.push({
        type: 'bestpractice',
        message: 'No instructions found',
        suggestion: 'Add .instruction() to explain the task to participants'
      });
    }

    // Check for very long experiments
    const trialCount = (code.match(/\.trial\(/g) || []).length;
    if (trialCount > 200) {
      warnings.push({
        type: 'bestpractice',
        message: `Large number of trials (${trialCount}) may cause fatigue`,
        suggestion: 'Consider adding breaks or reducing trial count'
      });
    }

    // Check for missing data logging
    if (!code.includes('.data(')) {
      warnings.push({
        type: 'bestpractice',
        message: 'No explicit data logging found',
        suggestion: 'Use .data() to store condition information with responses'
      });
    }
  }

  /**
   * Assess performance impact
   */
  private assessPerformance(code: string): ValidationResult['performanceImpact'] {
    const trialCount = (code.match(/\.trial\(/g) || []).length;
    const stimulusCount = (code.match(/\.stimulus\(/g) || []).length;
    const hasImages = code.includes('.image(');
    const hasVideo = code.includes('.video(');

    // Estimate duration
    const durationRegex = /\.duration\((\d+)\)/g;
    let totalDuration = 0;
    let match;

    while ((match = durationRegex.exec(code)) !== null) {
      totalDuration += parseInt(match[1]);
    }

    // Add ITI estimates
    const waitRegex = /\.wait\((\d+)\)/g;
    while ((match = waitRegex.exec(code)) !== null) {
      totalDuration += parseInt(match[1]);
    }

    // Estimate total duration with overhead
    const estimatedDuration = (totalDuration * trialCount) + (trialCount * 100); // 100ms overhead per trial

    // Estimate memory usage
    let memoryUsage = 10; // Base 10MB
    memoryUsage += trialCount * 0.1; // 100KB per trial
    memoryUsage += stimulusCount * 0.05; // 50KB per stimulus
    if (hasImages) memoryUsage += 20; // 20MB for image loading
    if (hasVideo) memoryUsage += 100; // 100MB for video buffering

    // Determine CPU intensity
    let cpuIntensity: 'low' | 'medium' | 'high' = 'low';
    if (hasVideo || trialCount > 100) cpuIntensity = 'medium';
    if (hasVideo && trialCount > 100) cpuIntensity = 'high';

    return {
      estimatedDuration,
      memoryUsage,
      cpuIntensity
    };
  }
}

