import { describe, it, expect, beforeEach, vi } from 'vitest';
import { AIDesignAssistant } from '../src/AIDesignAssistant.js';
import type { AIConfig, ExperimentContext, DesignCommand } from '../src/types.js';

// Mock the AI clients
vi.mock('openai', () => ({
  default: vi.fn().mockImplementation(() => ({
    chat: {
      completions: {
        create: vi.fn().mockResolvedValue({
          choices: [{
            message: {
              content: JSON.stringify({
                intent: 'add_stimulus',
                parameters: { type: 'text', content: 'TEST' },
                confidence: 0.9
              })
            }
          }]
        })
      }
    }
  }))
}));

vi.mock('@anthropic-ai/sdk', () => ({
  default: vi.fn().mockImplementation(() => ({
    messages: {
      create: vi.fn().mockResolvedValue({
        content: [{
          type: 'text',
          text: JSON.stringify({
            intent: 'add_stimulus',
            parameters: { type: 'text', content: 'TEST' },
            confidence: 0.9
          })
        }]
      })
    }
  }))
}));

describe('AIDesignAssistant', () => {
  let assistant: AIDesignAssistant;
  let config: AIConfig;
  let context: ExperimentContext;

  beforeEach(() => {
    config = {
      apiKey: 'test-key',
      model: 'gpt-4',
      temperature: 0.7
    };
    context = {
      experiment: undefined,
      selectedElement: undefined
    };
  });

  describe('constructor', () => {
    it('should create assistant with OpenAI model', () => {
      assistant = new AIDesignAssistant(config);
      expect(assistant).toBeDefined();
    });

    it('should create assistant with Anthropic model', () => {
      config.model = 'claude-3-opus';
      assistant = new AIDesignAssistant(config);
      expect(assistant).toBeDefined();
    });

    it('should throw error for unsupported model', () => {
      config.model = 'unsupported-model' as any;
      expect(() => new AIDesignAssistant(config)).toThrow('Unsupported AI model');
    });
  });

  describe('parseCommand', () => {
    beforeEach(() => {
      assistant = new AIDesignAssistant(config);
    });

    it('should parse add stimulus command', async () => {
      const command = await assistant.parseCommand('Add a red fixation cross', context);

      expect(command).toBeDefined();
      expect(command.intent).toBe('add_stimulus');
      expect(command.originalInput).toBe('Add a red fixation cross');
      expect(command.confidence).toBeGreaterThan(0);
    });

    it('should use fallback parsing on error', async () => {
      // Mock AI to throw error
      vi.mocked(assistant['openai']!.chat.completions.create).mockRejectedValueOnce(new Error('AI error'));

      const command = await assistant.parseCommand('Add 10 trials', context);

      expect(command.intent).toBe('add_trial');
      expect(command.parameters.count).toBe(10);
      expect(command.confidence).toBeLessThan(1);
    });

    it('should include context in parsed command', async () => {
      context.selectedElement = { type: 'trial', id: 'trial1' };

      const command = await assistant.parseCommand('Modify timing', context);

      expect(command.context.selectedElement).toEqual(context.selectedElement);
    });
  });

  describe('generateCode', () => {
    beforeEach(() => {
      assistant = new AIDesignAssistant(config);
    });

    it('should generate code for stimulus command', async () => {
      const command: DesignCommand = {
        intent: 'add_stimulus',
        parameters: { type: 'text', content: 'HELLO', color: 'blue' },
        confidence: 0.9,
        originalInput: 'Add blue text HELLO',
        context
      };

      const code = await assistant.generateCode(command);

      expect(code).toContain('experiment()');
      expect(code).toContain('.stimulus(');
      expect(code).toContain('HELLO');
    });
  });

  describe('validateCode', () => {
    beforeEach(() => {
      assistant = new AIDesignAssistant(config);
    });

    it('should validate correct code', async () => {
      const code = `
        experiment()
          .trial('test')
          .stimulus('text', 'TEST')
            .duration(1000)
          .response('keyboard')
            .timeout(2000);
      `;

      const result = await assistant.validateCode(code);

      expect(result.valid).toBe(true);
      expect(result.errors).toHaveLength(0);
    });

    it('should detect syntax errors', async () => {
      const code = `
        experiment()
          .trial('test'
          .stimulus('text', 'TEST')
      `; // Missing closing parenthesis

      const result = await assistant.validateCode(code);

      expect(result.valid).toBe(false);
