import { describe, it, expect, beforeEach } from 'vitest';
import { CodeGenerator } from '../src/CodeGenerator.js';
import type { DesignCommand } from '../src/types.js';

describe('CodeGenerator', () => {
  let generator: CodeGenerator;
  let baseCommand: DesignCommand;

  beforeEach(() => {
    generator = new CodeGenerator();
    baseCommand = {
      intent: 'add_stimulus',
      parameters: {},
      confidence: 0.9,
      originalInput: 'test',
      context: {}
    };
  });

  describe('generateFromCommand', () => {
    it('should generate stimulus code', async () => {
      baseCommand.parameters = {
        type: 'text',
        content: 'HELLO',
        color: 'red',
        fontSize: 48,
        duration: 1000
      };

      const code = await generator.generateFromCommand(baseCommand);

      expect(code).toContain('experiment()');
      expect(code).toContain('.stimulus(\'text_stim\', \'HELLO\')');
      expect(code).toContain('.fontSize(48)');
      expect(code).toContain('.color(\'red\')');
      expect(code).toContain('.duration(1000)');
    });

    it('should generate fixation cross', async () => {
      baseCommand.parameters = {
        type: 'fixation',
        color: 'white',
        duration: 500
      };

      const code = await generator.generateFromCommand(baseCommand);

      expect(code).toContain('.stimulus(\'fixation\', \'+\')');
      expect(code).toContain('.fontSize(24)');
      expect(code).toContain('.color(\'white\')');
    });

    it('should generate trial code', async () => {
      baseCommand.intent = 'add_trial';
      baseCommand.parameters = {
        count: 5,
        response: {
          keys: ['f', 'j'],
          timeout: 2000
        }
      };

      const code = await generator.generateFromCommand(baseCommand);

      expect(code).toContain('for (let i = 0; i < 5; i++)');
      expect(code).toContain('.trial(`trial_${i + 1}`)');
      expect(code).toContain('.response(\'keyboard\')');
      expect(code).toContain('.keys([\'f\', \'j\'])');
      expect(code).toContain('.timeout(2000)');
    });

    it('should generate Stroop trials', async () => {
      baseCommand.intent = 'add_trial';
      baseCommand.parameters = {
        count: 10,
        type: 'stroop',
        congruentRatio: 0.5
      };

      const code = await generator.generateFromCommand(baseCommand);

      expect(code).toContain('Stroop trials');
      expect(code).toContain('5 congruent, 5 incongruent');
      expect(code).toContain('colors[wordIdx]');
      expect(code).toContain('.data({ congruent:');
    });

    it('should generate block code', async () => {
      baseCommand.intent = 'add_block';
      baseCommand.parameters = {
        name: 'practice',
        trials: 5,
        instruction: 'Press SPACE to begin',
        feedback: 'Practice complete!'
      };

      const code = await generator.generateFromCommand(baseCommand);

      expect(code).toContain('.block(\'practice\')');
      expect(code).toContain('.instruction(\'Press SPACE to begin\')');
      expect(code).toContain('.trials(5,');
      expect(code).toContain('.feedback(\'Practice complete!\')');
    });

    it('should generate timing modification', async () => {
      baseCommand.intent = 'modify_timing';
      baseCommand.parameters = {
        duration: 1500,
        iti: 1000,
        jitter: 250
      };

      const code = await generator.generateFromCommand(baseCommand);

      expect(code).toContain('.duration(1500)');
      expect(code).toContain('750-1250ms');
      expect(code).toContain('Math.random()');
    });

    it('should generate instruction screen', async () => {
      baseCommand.intent = 'add_instruction';
      baseCommand.parameters = {
        text: 'Welcome to the experiment',
        fontSize: 24
      };

      const code = await generator.generateFromCommand(baseCommand);

      expect(code).toContain('.instruction(`Welcome to the experiment`)');
      expect(code).toContain('.fontSize(24)');
      expect(code).toContain('.continueKey(\'space\')');
    });

    it('should generate factorial design', async () => {
      baseCommand.intent = 'generate_factorial';
      baseCommand.parameters = {
        factors: {
          difficulty: ['easy', 'hard'],
          congruency: ['congruent', 'incongruent']
        }
      };

      const code = await generator.generateFromCommand(baseCommand);

      expect(code).toContain('2 x 2');
      expect(code).toContain('.conditions({');
      expect(code).toContain('difficulty: ["easy", "hard"]');
      expect(code).toContain('.factorial()');
    });

    it('should generate randomization', async () => {
      baseCommand.intent = 'add_randomization';
      baseCommand.parameters = {
        type: 'shuffle',
        seed: 12345
      };

      const code = await generator.generateFromCommand(baseCommand);

      expect(code).toContain('.shuffle()');
      expect(code).toContain('.seed(12345)');
    });

    it('should generate break screen', async () => {
      baseCommand.intent = 'add_break';
      baseCommand.parameters = {
        message: 'Take a 2 minute break',
        duration: 120000
      };

      const code = await generator.generateFromCommand(baseCommand);

      expect(code).toContain('.break(\'Take a 2 minute break\')');
      expect(code).toContain('.minimumDuration(120000)');
    });

    it('should throw error for unsupported intent', async () => {
      baseCommand.intent = 'unsupported' as any;

      await expect(generator.generateFromCommand(baseCommand))
        .rejects.toThrow('Code generation not implemented');
    });
  });

  describe('edge cases', () => {
    it('should handle missing parameters gracefully', async () => {
      baseCommand.parameters = {};

      const code = await generator.generateFromCommand(baseCommand);

      expect(code).toContain('experiment()');
      expect(code).toContain('.duration(1000)'); // Default duration
    });

    it('should handle empty factorial design', async () => {
      baseCommand.intent = 'generate_factorial';
      baseCommand.parameters = { factors: {} };

      const code = await generator.generateFromCommand(baseCommand);

      expect(code).toContain('No factors specified');
    });

    it('should generate single trial without loop', async () => {
      baseCommand.intent = 'add_trial';
      baseCommand.parameters = { count: 1 };

      const code = await generator.generateFromCommand(baseCommand);

      expect(code).not.toContain('for (');
      expect(code).toContain('.trial(\'trial_1\')');
    });
  });
});

