/**
 * Demo of AI Design Assistant capabilities
 */

import { AIDesignAssistant } from '../src/index.js';
import type { ExperimentContext } from '../src/types.js';

// Initialize the assistant
const assistant = new AIDesignAssistant({
  apiKey: process.env.OPENAI_API_KEY || 'demo-key',
  model: 'gpt-4',
  temperature: 0.7
});

// Example context (current experiment state)
const context: ExperimentContext = {
  experiment: {
    name: 'Stroop Task',
    blocks: [
      { id: 'practice', trials: 10 },
      { id: 'main', trials: 80 }
    ]
  } as any,
  selectedElement: {
    type: 'block',
    id: 'main'
  }
};

async function demonstrateAIAssistant() {
  console.log('🤖 Psycho-Forge AI Assistant Demo\n');

  // Example 1: Parse natural language commands
  console.log('1. Parsing Natural Language Commands:');
  const commands = [
    'Add a red fixation cross for 500ms',
    'Create 20 Stroop trials with equal congruent and incongruent',
    'Set keyboard responses with 2 second timeout',
    'Add instructions explaining the task'
  ];

  for (const cmd of commands) {
    console.log(`\n  Command: "${cmd}"`);
    try {
      const parsed = await assistant.parseCommand(cmd, context);
      console.log(`  Intent: ${parsed.intent}`);
      console.log(`  Parameters:`, parsed.parameters);
      console.log(`  Confidence: ${(parsed.confidence * 100).toFixed(0)}%`);
    } catch (error) {
      console.log(`  Error: ${error.message}`);
    }
  }

  // Example 2: Generate ForgeScript code
  console.log('\n\n2. Generating ForgeScript Code:');
  const designCommand = {
    intent: 'add_trial' as const,
    parameters: {
      count: 10,
      type: 'stroop',
      congruentRatio: 0.5
    },
    confidence: 0.95,
