/**
 * Code generator for ForgeScript from AI commands
 */

import type { DesignCommand } from './types.js';
import { COMMAND_PROMPTS, FORGESRIPT_EXAMPLES } from './prompts.js';

/**
 * Generates ForgeScript code from parsed commands
 */
export class CodeGenerator {
  /**
   * Generate code from a design command
   */
  async generateFromCommand(command: DesignCommand): Promise<string> {
    switch (command.intent) {
      case 'add_stimulus':
        return this.generateStimulus(command.parameters);

      case 'add_trial':
        return this.generateTrial(command.parameters);

      case 'add_block':
        return this.generateBlock(command.parameters);

      case 'modify_timing':
        return this.generateTimingModification(command.parameters);

      case 'add_condition':
        return this.generateCondition(command.parameters);

      case 'add_response':
        return this.generateResponse(command.parameters);

      case 'add_instruction':
        return this.generateInstruction(command.parameters);

      case 'generate_factorial':
        return this.generateFactorial(command.parameters);

      case 'add_randomization':
        return this.generateRandomization(command.parameters);

      case 'add_break':
        return this.generateBreak(command.parameters);

      default:
        throw new Error(`Code generation not implemented for intent: ${command.intent}`);
    }
  }

  /**
   * Generate stimulus code
   */
  private generateStimulus(params: Record<string, any>): string {
    const { type = 'text', content = 'X', duration = 1000, color, fontSize, position } = params;

    let code = `experiment()\n  .trial('stimulus_trial')\n`;

    switch (type) {
      case 'text':
      case 'word':
        code += `    .stimulus('text_stim', '${content}')\n`;
        if (fontSize) code += `      .fontSize(${fontSize})\n`;
        if (color) code += `      .color('${color}')\n`;
        break;

      case 'cross':
      case 'fixation':
        code += `    .stimulus('fixation', '+')\n`;
        code += `      .fontSize(${fontSize || 24})\n`;
        if (color) code += `      .color('${color}')\n`;
        break;

      case 'image':
        code += `    .stimulus('image_stim', '${content}')\n`;
        code += `      .size(${params.width || 200}, ${params.height || 200})\n`;
        break;

      case 'shape':
        const shape = params.shape || 'circle';
        code += `    .shape('shape_stim', '${shape}')\n`;
        if (params.size) code += `      .size(${params.size})\n`;
        if (color) code += `      .color('${color}')\n`;
        break;
    }

    if (position) {
      code += `      .position(${position.x || 0}, ${position.y || 0})\n`;
    }

    code += `      .duration(${duration});`;

    return code;
  }

  /**
   * Generate trial code
   */
  private generateTrial(params: Record<string, any>): string {
    const { count = 1, type = 'basic', stimuli = [], response, iti = 1000 } = params;

    if (type === 'stroop') {
      return this.generateStroopTrials(count, params);
    }

    let code = '';

    if (count > 1) {
      code += `// Generate ${count} trials\n`;
      code += `for (let i = 0; i < ${count}; i++) {\n`;
      code += `  experiment()\n`;
      code += `    .trial(\`trial_\${i + 1}\`)\n`;
    } else {
      code += `experiment()\n`;
      code += `  .trial('trial_1')\n`;
    }

    // Add stimuli
    if (stimuli.length > 0) {
      stimuli.forEach((stim: any, idx: number) => {
        code += `    .stimulus('stim_${idx + 1}', '${stim.content || 'X'}')\n`;
        if (stim.duration) code += `      .duration(${stim.duration})\n`;
      });
    } else {
      // Default stimulus
      code += `    .stimulus('target', 'X')\n`;
      code += `      .duration(1000)\n`;
    }

    // Add response collection
    if (response) {
      code += `    .response('keyboard')\n`;
      if (response.keys) code += `      .keys([${response.keys.map((k: string) => `'${k}'`).join(', ')}])\n`;
      if (response.timeout) code += `      .timeout(${response.timeout})\n`;
    }

    // Add ITI
    code += `    .wait(${iti})`;

    if (count > 1) {
      code += `;\n}`;
    } else {
      code += ';';
    }

    return code;
  }

  /**
   * Generate Stroop trials
   */
  private generateStroopTrials(count: number, params: Record<string, any>): string {
    const { congruentRatio = 0.5, colors = ['RED', 'BLUE', 'GREEN', 'YELLOW'] } = params;
    const congruentCount = Math.floor(count * congruentRatio);
    const incongruentCount = count - congruentCount;

    return `// Generate ${count} Stroop trials (${congruentCount} congruent, ${incongruentCount} incongruent)
const colors = ${JSON.stringify(colors)};
const conditions = [];

// Generate congruent trials
for (let i = 0; i < ${congruentCount}; i++) {
  const color = colors[i % colors.length];
  conditions.push({ word: color, color: color.toLowerCase(), congruent: true });
}

// Generate incongruent trials
for (let i = 0; i < ${incongruentCount}; i++) {
  const wordIdx = i % colors.length;
  const colorIdx = (i + 1) % colors.length;
  conditions.push({ 
    word: colors[wordIdx], 
    color: colors[colorIdx].toLowerCase(), 
    congruent: false 
  });
}

// Shuffle conditions
conditions.sort(() => Math.random() - 0.5);

// Create trials
conditions.forEach((cond, i) => {
  experiment()
    .trial(\`stroop_\${i + 1}\`)
    .stimulus('word', cond.word)
      .fontSize(48)
      .color(cond.color)
      .duration(2000)
    .response('keyboard')
      .keys(['r', 'g', 'b', 'y'])
      .timeout(2000)
      .data({ congruent: cond.congruent, word: cond.word, color: cond.color })
    .wait(1000);
});`;
  }

  /**
   * Generate block code
   */
  private generateBlock(params: Record<string, any>): string {
    const { name = 'block', trials = 10, instruction, feedback } = params;

    let code = `experiment()\n`;
    code += `  .block('${name}')\n`;

    if (instruction) {
      code += `    .instruction('${instruction}')\n`;
    }

    code += `    .trials(${trials}, (i) => \n`;
    code += `      experiment()\n`;
    code += `        .trial(\`\${name}_trial_\${i + 1}\`)\n`;
    code += `        .stimulus('target', 'X')\n`;
    code += `          .duration(1000)\n`;
    code += `        .response('keyboard')\n`;
    code += `          .timeout(2000)\n`;
    code += `    )\n`;

    if (feedback) {
      code += `    .feedback('${feedback}')`;
    }

    code += ';';

    return code;
  }

  /**
   * Generate timing modification code
   */
  private generateTimingModification(params: Record<string, any>): string {
    const { target, duration, iti, jitter } = params;

    let code = '// Timing modifications\n';

    if (duration !== undefined) {
      code += `// Set stimulus duration to ${duration}ms\n`;
      code += `.duration(${duration})\n`;
    }

    if (iti !== undefined) {
      if (jitter) {
        const min = iti - jitter;
        const max = iti + jitter;
        code += `// Set ITI with jitter: ${min}-${max}ms\n`;
        code += `.wait(() => ${min} + Math.random() * ${max - min})\n`;
      } else {
        code += `// Set fixed ITI: ${iti}ms\n`;
        code += `.wait(${iti})\n`;
      }
    }

    return code;
  }

  /**
   * Generate condition code
   */
  private generateCondition(params: Record<string, any>): string {
    const { name, values } = params;

    return `experiment()
  .condition('${name}', ${JSON.stringify(values)})`;
  }

  /**
   * Generate response collection code
   */
  private generateResponse(params: Record<string, any>): string {
    const { type = 'keyboard', keys = ['space'], timeout = 3000, correct } = params;

    let code = `.response('${type}')\n`;

    if (type === 'keyboard') {
      code += `  .keys(${JSON.stringify(keys)})\n`;
      if (correct) code += `  .correctKey('${correct}')\n`;
    }

    code += `  .timeout(${timeout})`;

    return code;
  }

  /**
   * Generate instruction screen code
   */
  private generateInstruction(params: Record<string, any>): string {
    const { text, fontSize = 20, continueKey = 'space' } = params;

    return `experiment()
  .instruction(\`${text}\`)
    .fontSize(${fontSize})
    .continueKey('${continueKey}');`;
  }

  /**
   * Generate factorial design code
   */
  private generateFactorial(params: Record<string, any>): string {
    const { factors = {} } = params;
    const factorEntries = Object.entries(factors);

    if (factorEntries.length === 0) {
      return '// No factors specified for factorial design';
    }

    let code = `// Factorial design: ${factorEntries.map(([k, v]) => `${k}(${Array.isArray(v) ? v.length : 0})`).join(' x ')}\n`;
    code += `experiment()\n`;
    code += `  .conditions({\n`;

    factorEntries.forEach(([factor, levels], idx) => {
      code += `    ${factor}: ${JSON.stringify(levels)}`;
      if (idx < factorEntries.length - 1) code += ',';
      code += '\n';
    });

    code += `  })\n`;
    code += `  .factorial()\n`;
    code += `  .trial('factorial_trial', (condition) => {\n`;
    code += `    // Configure trial based on condition\n`;
    code += `    console.log('Condition:', condition);\n`;
    code += `  });`;

    return code;
  }

  /**
   * Generate randomization code
   */
  private generateRandomization(params: Record<string, any>): string {
    const { type = 'shuffle', seed } = params;

    let code = '';

    if (type === 'shuffle') {
      code += `// Shuffle trials\n`;
      code += `.shuffle()`;
      if (seed) code += `\n  .seed(${seed})`;
    } else if (type === 'latin_square') {
      code += `// Latin square counterbalancing\n`;
      code += `.latinSquare()`;
    }

    return code;
  }

  /**
   * Generate break screen code
   */
  private generateBreak(params: Record<string, any>): string {
    const { message = 'Take a break. Press SPACE to continue.', duration } = params;

    let code = `experiment()\n`;
    code += `  .break('${message}')`;

    if (duration) {
      code += `\n    .minimumDuration(${duration})`;
    }

    code += `;`;

    return code;
  }
}

