import { describe, it, expect, beforeEach } from 'vitest';
import { CodeValidator } from '../src/CodeValidator.js';

describe('CodeValidator', () => {
  let validator: CodeValidator;

  beforeEach(() => {
    validator = new CodeValidator();
  });

  describe('validate', () => {
    it('should validate correct code', async () => {
      const code = `
experiment()
  .trial('test')
    .stimulus('text', 'HELLO')
      .duration(1000)
    .response('keyboard')
      .keys(['f', 'j'])
      .timeout(2000)
    .wait(1000);
`;

      const result = await validator.validate(code);

      expect(result.valid).toBe(true);
      expect(result.errors).toHaveLength(0);
    });

    it('should detect syntax errors - unmatched parentheses', async () => {
      const code = `
experiment()
  .trial('test'
    .stimulus('text', 'HELLO')
`;

      const result = await validator.validate(code);

      expect(result.valid).toBe(false);
      expect(result.errors).toContainEqual(
        expect.objectContaining({
          type: 'syntax',
          message: expect.stringContaining('parentheses')
        })
      );
    });

    it('should detect missing semicolons', async () => {
      const code = `
experiment()
  .trial('test')
    .stimulus('text', 'HELLO')
      .duration(1000)

experiment()
  .trial('test2')
`;

      const result = await validator.validate(code);

      expect(result.valid).toBe(false);
      expect(result.errors).toContainEqual(
        expect.objectContaining({
          type: 'syntax',
          message: 'Missing semicolon'
        })
      );
    });

    it('should warn about stimulus without duration', async () => {
      const code = `
experiment()
  .trial('test')
    .stimulus('text', 'HELLO')
    .response('keyboard');
`;

      const result = await validator.validate(code);

      expect(result.valid).toBe(true); // Warning, not error
      expect(result.warnings).toContainEqual(
        expect.objectContaining({
          type: 'bestpractice',
          message: expect.stringContaining('duration')
        })
      );
    });

    it('should warn about response without timeout', async () => {
      const code = `
experiment()
  .trial('test')
    .stimulus('text', 'HELLO')
      .duration(1000)
    .response('keyboard')
      .keys(['f', 'j']);
`;

      const result = await validator.validate(code);

      expect(result.warnings).toContainEqual(
        expect.objectContaining({
          type: 'bestpractice',
          message: expect.stringContaining('timeout')
        })
      );
    });

    it('should warn about trial without response', async () => {
      const code = `
experiment()
  .trial('test')
    .stimulus('text', 'HELLO')
      .duration(1000);
`;

      const result = await validator.validate(code);

      expect(result.warnings).toContainEqual(
        expect.objectContaining({
          type: 'bestpractice',
          message: expect.stringContaining('response collection')
        })
      );
    });

    it('should error on very short durations', async () => {
      const code = `
experiment()
  .trial('test')
    .stimulus('text', 'HELLO')
      .duration(10);
`;

      const result = await validator.validate(code);

      expect(result.valid).toBe(false);
      expect(result.errors).toContainEqual(
        expect.objectContaining({
          type: 'timing',
          message: expect.stringContaining('shorter than one frame')
        })
      );
    });

    it('should warn about short durations', async () => {
      const code = `
experiment()
  .trial('test')
    .stimulus('text', 'HELLO')
      .duration(30);
`;

      const result = await validator.validate(code);

      expect(result.warnings).toContainEqual(
        expect.objectContaining({
          type: 'performance',
          message: expect.stringContaining('Very short duration')
        })
      );
    });

    it('should warn about missing practice trials', async () => {
      const code = `
experiment()
  .trial('main_1')
    .stimulus('text', 'TEST')
      .duration(1000);
`;

      const result = await validator.validate(code);

      expect(result.warnings).toContainEqual(
        expect.objectContaining({
          type: 'bestpractice',
          message: expect.stringContaining('practice trials')
        })
      );
    });

    it('should warn about missing instructions', async () => {
      const code = `
experiment()
  .trial('test')
    .stimulus('text', 'HELLO')
      .duration(1000);
`;

      const result = await validator.validate(code);

      expect(result.warnings).toContainEqual(
        expect.objectContaining({
          type: 'bestpractice',
          message: expect.stringContaining('instructions')
        })
      );
    });

    it('should warn about very long experiments', async () => {
      let code = '';
      for (let i = 0; i < 250; i++) {
        code += `
experiment()
  .trial('trial_${i}')
    .stimulus('text', 'X')
      .duration(1000);
`;
      }

      const result = await validator.validate(code);

      expect(result.warnings).toContainEqual(
        expect.objectContaining({
          type: 'bestpractice',
          message: expect.stringContaining('fatigue')
        })
      );
    });

    it('should assess performance impact', async () => {
      const code = `
experiment()
  .trial('test')
    .stimulus('text', 'HELLO')
      .duration(1000)
    .wait(500);
`;

      const result = await validator.validate(code);

      expect(result.performanceImpact).toBeDefined();
      expect(result.performanceImpact!.estimatedDuration).toBeGreaterThan(0);
      expect(result.performanceImpact!.memoryUsage).toBeGreaterThan(0);
      expect(result.performanceImpact!.cpuIntensity).toBe('low');
    });

    it('should assess higher CPU intensity for video', async () => {
      let code = `experiment().video('intro', 'video.mp4');\n`;

      for (let i = 0; i < 150; i++) {
        code += `experiment().trial('t${i}');\n`;
      }

      const result = await validator.validate(code);

      expect(result.performanceImpact!.cpuIntensity).toBe('high');
      expect(result.performanceImpact!.memoryUsage).toBeGreaterThan(100);
    });
  });

  describe('edge cases', () => {
    it('should handle empty code', async () => {
      const result = await validator.validate('');

      expect(result.valid).toBe(true);
      expect(result.errors).toHaveLength(0);
    });

    it('should handle code with only comments', async () => {
      const code = `
